37→export function buildPreviewScene(project, options = {}) {
38→  const floors = getOrderedFloors(project);
39→  const activeFloorId = getDefaultActiveFloorId(project, options.activeFloorId);
40→  const activeFloor = floors.find((floor) => floor.id === activeFloorId) || null;
41→  const stackBounds = getFloorStackBounds(floors);
42→  const resolvedVisibleFloorIds = options.visibleFloorIds || floors.map((floor) => floor.id);
43→  const visibleFloorIds = new Set(resolvedVisibleFloorIds);
44→
45→  const floorDescriptors = floors.map((floor) => {
46→    const objects = buildFloorPreviewObjects(floor);
47→    return {
48→      floorId: floor.id,
49→      name: floor.name,
50→      elevation: getFloorElevation(floor),
51→      visible: visibleFloorIds.has(floor.id),
52→      objects,
53→      bounds: boundsFromObjects(objects),
54→    };
55→  });
56→
57→  const visibleObjects = floorDescriptors
58→    .filter((floor) => floor.visible)
59→    .flatMap((floor) => floor.objects);
60→  const bounds = boundsFromObjects(visibleObjects) || createFallbackBounds(stackBounds, activeFloor);
61→
62→  return {
63→    activeFloorId,
64→    visibleFloorIds: [...visibleFloorIds],
65→    floors: floorDescriptors,
66→    bounds,
67→    defaultTarget: {
68→      x: (bounds.minX + bounds.maxX) / 2,
69→      y: (bounds.minElevation + bounds.maxElevation) / 2,
70→      z: (bounds.minY + bounds.maxY) / 2,
71→    },
72→    groundLevel: stackBounds.minElevation,
73→    hasVisibleObjects: visibleObjects.length > 0,
74→  };
75→}
