  1→import { generateId } from './ids';
  2→import { WALL_THICKNESS, WALL_HEIGHT, DOOR_WIDTH, DOOR_HEIGHT, DOOR_SILL_HEIGHT, WINDOW_WIDTH, WINDOW_HEIGHT, WINDOW_SILL_HEIGHT, COLUMN_WIDTH, COLUMN_DEPTH, BEAM_WIDTH, BEAM_DEPTH, STAIR_WIDTH, STAIR_RISERS, STAIR_RISER_HEIGHT, STAIR_TREAD_DEPTH, SLAB_THICKNESS, SLAB_ELEVATION, SECTION_DEPTH, LANDING_WIDTH, LANDING_DEPTH, LANDING_THICKNESS, ROOM_COLOR, DIMENSION_DEFAULT_OFFSET } from './defaults';
  3→import { polygonArea, polygonCentroid } from '@/geometry/polygon';
  4→
  5→export function createProject(name = 'Untitled Project') {
  6→  return {
  7→    id: generateId('proj'),
  8→    name,
  9→    createdAt: new Date().toISOString(),
 10→    updatedAt: new Date().toISOString(),
 11→    floors: [createFloor('Ground Floor', 0, { elevation: 0, floorToFloorHeight: WALL_HEIGHT })],
 12→    sheets: [],
 13→    version: 1,
 14→  };
 15→}
 16→
 17→export function createFloor(name = 'Floor', levelIndex = 0, options = {}) {
 18→  const floorToFloorHeight = options.floorToFloorHeight ?? WALL_HEIGHT;
 19→  const elevation = options.elevation ?? (levelIndex * floorToFloorHeight);
 20→
 21→  return {
 22→    id: generateId('floor'),
 23→    name,
 24→    levelIndex,
 25→    elevation,
 26→    floorToFloorHeight,
 27→    walls: [],
 28→    rooms: [],
 29→    doors: [],
 30→    windows: [],
 31→    columns: [],
 32→    beams: [],
 33→    stairs: [],
 34→    landings: [],
 35→    annotations: [],
 36→    annotationSettings: createAnnotationSettings(),
 37→    slabs: [],
 38→    sectionCuts: [],
 39→  };
 40→}
 41→
 42→export function nextSectionLabel(existingCuts = []) {
 43→  const usedLetters = new Set(
 44→    existingCuts
 45→      .map(c => {
 46→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 47→        return match ? match[1] : null;
 48→      })
 49→      .filter(Boolean)
 50→  );
 51→  for (let i = 0; i < 26; i++) {
 52→    const letter = String.fromCharCode(65 + i);
 53→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 54→  }
 55→  return `Section ${existingCuts.length + 1}`;
 56→}
 57→
 58→export function createAnnotationSettings(overrides = {}) {
 59→  return {
 60→    showWallDimensions: overrides.showWallDimensions ?? true,
 61→    showRoomDimensions: overrides.showRoomDimensions ?? true,
 62→    showOverallDimensions: overrides.showOverallDimensions ?? true,
 63→    showObjectTags: overrides.showObjectTags ?? true,
 64→    showElevationOverallDimensions: overrides.showElevationOverallDimensions ?? true,
 65→    showElevationLevelDimensions: overrides.showElevationLevelDimensions ?? true,
 66→    showElevationOpeningDimensions: overrides.showElevationOpeningDimensions ?? true,
 67→  };
 68→}
 69→
 70→export function createLinearDimensionAnnotation(startPoint, endPoint, options = {}) {
