  1→import { add, subtract, scale, normalize, perpendicular, distance, midpoint } from './point';
  2→import { columnCenter, columnOutline } from './columnGeometry';
  3→
  4→const EPSILON = 1e-6;
  5→
  6→function makeOutline(start, end, width) {
  7→  const direction = normalize(subtract(end, start));
  8→  const offset = scale(perpendicular(direction), width / 2);
  9→  return [
 10→    add(start, offset),
 11→    add(end, offset),
 12→    subtract(end, offset),
 13→    subtract(start, offset),
 14→  ];
 15→}
 16→
 17→function findColumn(columns, ref) {
 18→  if (!ref || ref.kind !== 'column') return null;
 19→  return (columns || []).find((column) => column.id === ref.id) || null;
 20→}
 21→
 22→function raySegmentIntersection(origin, direction, start, end) {
 23→  const segment = subtract(end, start);
 24→  const cross = direction.x * segment.y - direction.y * segment.x;
 25→  if (Math.abs(cross) < EPSILON) return null;
 26→
 27→  const delta = subtract(start, origin);
 28→  const t = (delta.x * segment.y - delta.y * segment.x) / cross;
 29→  const u = (delta.x * direction.y - delta.y * direction.x) / cross;
 30→
 31→  if (t < -EPSILON || u < -EPSILON || u > 1 + EPSILON) return null;
 32→
 33→  return {
 34→    t,
 35→    point: add(origin, scale(direction, Math.max(0, t))),
 36→  };
 37→}
 38→
 39→function trimPoint(origin, otherPoint, column) {
 40→  if (!column) return { ...origin };
 41→
 42→  const direction = normalize(subtract(otherPoint, origin));
 43→  if (Math.abs(direction.x) < EPSILON && Math.abs(direction.y) < EPSILON) {
 44→    return { ...origin };
 45→  }
 46→
 47→  const polygon = columnOutline(column);
 48→  let best = null;
 49→
 50→  for (let i = 0; i < polygon.length; i += 1) {
 51→    const hit = raySegmentIntersection(origin, direction, polygon[i], polygon[(i + 1) % polygon.length]);
 52→    if (!hit) continue;
 53→    if (!best || hit.t < best.t) {
 54→      best = hit;
 55→    }
 56→  }
 57→
 58→  return best ? best.point : { ...origin };
 59→}
 60→
 61→export function resolveBeamColumns(beam, columns = []) {
 62→  return {
 63→    startColumn: findColumn(columns, beam.startRef),
 64→    endColumn: findColumn(columns, beam.endRef),
 65→  };
 66→}
 67→
 68→export function resolveBeamAxis(beam, columns = []) {
 69→  const { startColumn, endColumn } = resolveBeamColumns(beam, columns);
 70→  if (!startColumn || !endColumn || startColumn.id === endColumn.id) return null;
 71→
 72→  return {
 73→    startColumn,
 74→    endColumn,
 75→    startCenter: columnCenter(startColumn),
 76→    endCenter: columnCenter(endColumn),
 77→  };
 78→}
 79→
 80→export function getBeamRenderData(beam, columns = []) {
 81→  const axis = resolveBeamAxis(beam, columns);
 82→  if (!axis) return null;
 83→
 84→  const start = trimPoint(axis.startCenter, axis.endCenter, axis.startColumn);
 85→  const end = trimPoint(axis.endCenter, axis.startCenter, axis.endColumn);
 86→  const outline = makeOutline(start, end, beam.width);
 87→
 88→  return {
 89→    beam,
 90→    start,
 91→    end,
 92→    outline,
 93→    midpoint: midpoint(start, end),
 94→    length: distance(start, end),
 95→    startColumn: axis.startColumn,
 96→    endColumn: axis.endColumn,
 97→  };
 98→}
 99→
100→export function beamLength(beam, columns = []) {
101→  return getBeamRenderData(beam, columns)?.length || 0;
102→}
