320→export function buildManualDimensionFigures(annotations = []) {
321→  return annotations
322→    .filter((annotation) => annotation.type === 'dimension')
323→    .map((annotation) => createDimensionFigure({
324→      id: annotation.id,
325→      startPoint: annotation.startPoint,
326→      endPoint: annotation.endPoint,
327→      mode: annotation.mode,
328→      offset: annotation.offset,
329→      label: annotation.textOverride?.trim() || undefined,
330→      source: 'manual',
331→      sourceType: 'annotation',
332→      sourceId: annotation.id,
333→    }))
334→    .filter(Boolean);
335→}
