274→function computeSceneBounds(rects, stairs, sectionCut, baseLevel) {
275→  const stairXs = stairs.flatMap((element) => element.points.map((point) => point.x));
276→  const stairZs = stairs.flatMap((element) => element.points.map((point) => point.z));
277→  const rectXs = rects.flatMap((element) => [element.left, element.right]);
278→  const rectZs = rects.flatMap((element) => [element.bottom, element.top]);
279→  const xs = [...rectXs, ...stairXs];
280→  const zs = [...rectZs, ...stairZs];
281→
282→  if (!xs.length || !zs.length) {
283→    return {
284→      minX: 0,
285→      maxX: sectionCutLength(sectionCut) || 3000,
286→      minZ: baseLevel,
287→      maxZ: baseLevel + 3000,
288→    };
289→  }
290→
291→  return {
292→    minX: Math.min(...xs),
293→    maxX: Math.max(...xs),
294→    minZ: Math.min(baseLevel, ...zs),
295→    maxZ: Math.max(...zs),
296→  };
297→}
298→
299→function resolveLandingElevation(landing, stairs, floorLevel) {
300→  if (landing.elevation) return landing.elevation;
301→  return computeLandingElevation(landing, stairs, floorLevel) - floorLevel;
302→}
303→
304→function buildFloorSectionElements(floor, sectionCut) {
305→  const floorElevation = getFloorElevation(floor);
306→  const landings = floor.landings || [];
307→  const stairs = floor.stairs || [];
308→
309→  const landingElevationMap = new Map(
310→    landings.map(l => [l.id, resolveLandingElevation(l, stairs, floorElevation)])
311→  );
312→
313→  return {
314→    rectElements: [
315→      ...buildWallElements(floor, sectionCut),
316→      ...buildSlabElements(floor, sectionCut),
317→      ...buildColumnElements(floor, sectionCut),
318→      ...buildBeamElements(floor, sectionCut),
319→      ...buildDoorElements(floor, sectionCut),
320→      ...buildWindowElements(floor, sectionCut),
321→    ],
322→    stairElements: buildStairElements(floor, sectionCut, landingElevationMap),
323→  };
324→}
325→
326→function buildSectionSceneFromFloors(floors, sectionCut, title = null) {
327→  if (!sectionCut) return null;
328→
329→  const stackBounds = getFloorStackBounds(floors);
330→  const rectElements = [];
331→  const stairElements = [];
332→
333→  for (const floor of floors) {
334→    const floorElements = buildFloorSectionElements(floor, sectionCut);
335→    rectElements.push(...floorElements.rectElements);
336→    stairElements.push(...floorElements.stairElements);
337→  }
338→
339→  const sortedRectElements = rectElements.sort((a, b) => {
340→    if (a.renderMode !== b.renderMode) return a.renderMode === 'projection' ? -1 : 1;
341→    return b.depth - a.depth;
342→  });
343→
344→  const sortedStairElements = stairElements.sort((a, b) => {
345→    if (a.renderMode !== b.renderMode) return a.renderMode === 'projection' ? -1 : 1;
346→    return b.depth - a.depth;
347→  });
348→
349→  return {
350→    viewKey: 'section_view',
351→    title: title || sectionCut.label || 'Section',
352→    rectElements: sortedRectElements,
353→    stairElements: sortedStairElements,
354→    bounds: computeSceneBounds(sortedRectElements, sortedStairElements, sectionCut, stackBounds.minElevation),
355→    groundLevel: stackBounds.minElevation,
356→  };
357→}
358→
359→export function buildSectionScene(floor, sectionCut) {
360→  if (!floor || !sectionCut) return null;
361→  return buildSectionSceneFromFloors([floor], sectionCut, sectionCut.label || 'Section');
362→}
