364→export function buildProjectSectionScene(project, sourceFloorId, sectionCutId = null) {
365→  const sourceFloor = resolveProjectFloor(project, sourceFloorId);
366→  if (!sourceFloor) return null;
367→
368→  const cuts = sourceFloor.sectionCuts || [];
369→  const sectionCut = sectionCutId
370→    ? cuts.find((entry) => entry.id === sectionCutId)
371→    : cuts[0] || null;
372→  if (!sectionCut) return null;
373→
374→  return buildSectionSceneFromFloors(
375→    getOrderedFloors(project),
376→    sectionCut,
377→    sectionCut.label || 'Section'
378→  );
379→}
