 29→function buildWallRects(floor, view) {
 30→  const floorElevation = getFloorElevation(floor);
 31→  return (floor.walls || [])
 32→    .map((wall) => {
 33→      const renderData = getWallRenderData(wall, floor.columns || []);
 34→      return createSceneRect(
 35→        `wall-elev-${wall.id}`,
 36→        'wall',
 37→        projectPlanPoints(view, renderData.outline),
 38→        floorElevation,
 39→        floorElevation + (wall.height ?? 0),
 40→        { sourceId: wall.id }
 41→      );
 42→    })
 43→    .filter(Boolean);
 44→}
 45→
 46→function buildSlabRects(floor, view) {
 47→  return (floor.slabs || []).flatMap((slab) => {
 48→    const slabTop = getSlabTopLevel(slab);
 49→    const slabBottom = getSlabBottomLevel(slab);
 50→
 51→    return buildSlabElevationBands(slab, view)
 52→      .map((band) => createSceneRect(
 53→        `slab-elev-${slab.id}-${band.edgeIndex}`,
 54→        'slab',
 55→        band,
 56→        slabBottom,
 57→        slabTop,
 58→        { sourceId: slab.id }
 59→      ))
 60→      .filter(Boolean);
 61→  });
 62→}
 63→
 64→function buildColumnRects(floor, view) {
 65→  const floorElevation = getFloorElevation(floor);
 66→  return (floor.columns || [])
 67→    .map((column) => createSceneRect(
 68→      `column-elev-${column.id}`,
 69→      'column',
 70→      projectPlanPoints(view, columnOutline(column)),
 71→      floorElevation,
 72→      floorElevation + column.height,
 73→      { sourceId: column.id }
 74→    ))
 75→    .filter(Boolean);
 76→}
 77→
 78→function buildBeamRects(floor, view) {
 79→  return (floor.beams || [])
 80→    .map((beam) => {
 81→      const renderData = getBeamRenderData(beam, floor.columns || []);
 82→      if (!renderData) return null;
 83→      return createSceneRect(
 84→        `beam-elev-${beam.id}`,
 85→        'beam',
 86→        projectPlanPoints(view, renderData.outline),
 87→        beam.floorLevel - beam.depth,
 88→        beam.floorLevel,
 89→        { sourceId: beam.id }
 90→      );
 91→    })
 92→    .filter(Boolean);
 93→}
 94→
 95→function buildStairRects(floor, view, landingElevationMap) {
 96→  const floorElevation = getFloorElevation(floor);
 97→  return (floor.stairs || [])
 98→    .map((stair) => {
 99→      const renderData = getStairRenderData(stair);
100→      if (!renderData?.outline?.length) return null;
101→
102→      let baseElevation = floorElevation;
103→      if (stair.startLandingAttachment) {
104→        const elev = landingElevationMap?.get(stair.startLandingAttachment.landingId);
105→        if (elev != null) {
106→          baseElevation = floorElevation + elev;
107→        }
108→      }
109→
110→      return createSceneRect(
111→        `stair-elev-${stair.id}`,
112→        'stair',
113→        projectPlanPoints(view, renderData.outline),
114→        baseElevation,
115→        baseElevation + renderData.totalRise,
116→        { sourceId: stair.id }
117→      );
118→    })
119→    .filter(Boolean);
120→}
121→
122→function buildDoorRects(floor, view) {
123→  const floorElevation = getFloorElevation(floor);
124→  return (floor.doors || [])
125→    .map((door) => {
126→      const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
127→      if (!wall) return null;
128→      const info = doorOutlineOnWall(wall, door);
129→      return createSceneRect(
130→        `door-elev-${door.id}`,
131→        'door',
132→        projectPlanPoints(view, [info.p1, info.p2, info.p3, info.p4]),
133→        floorElevation + (door.sillHeight ?? 0),
134→        floorElevation + (door.sillHeight ?? 0) + (door.height ?? 0),
135→        { sourceId: door.id }
136→      );
137→    })
138→    .filter(Boolean);
139→}
140→
141→function buildWindowRects(floor, view) {
142→  const floorElevation = getFloorElevation(floor);
143→  return (floor.windows || [])
144→    .map((windowItem) => {
145→      const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
146→      if (!wall) return null;
147→      const info = windowOutlineOnWall(wall, windowItem);
148→      return createSceneRect(
149→        `window-elev-${windowItem.id}`,
150→        'window',
151→        projectPlanPoints(view, [info.p1, info.p2, info.p3, info.p4]),
152→        floorElevation + (windowItem.sillHeight ?? 0),
153→        floorElevation + (windowItem.sillHeight ?? 0) + (windowItem.height ?? 0),
154→        { sourceId: windowItem.id }
155→      );
156→    })
157→    .filter(Boolean);
158→}
159→
160→function computeSceneBounds(elements = [], baseLevel = 0) {
161→  if (!elements.length) {
162→    return {
163→      minX: -1000,
164→      maxX: 1000,
165→      minZ: baseLevel,
166→      maxZ: baseLevel + 3000,
167→    };
168→  }
169→
170→  return {
171→    minX: Math.min(...elements.map((element) => element.left)),
172→    maxX: Math.max(...elements.map((element) => element.right)),
173→    minZ: Math.min(baseLevel, ...elements.map((element) => element.bottom)),
174→    maxZ: Math.max(...elements.map((element) => element.top)),
175→  };
176→}
177→
178→function resolveLandingElevation(landing, stairs, floorLevel) {
179→  if (landing.elevation) return landing.elevation;
180→  return computeLandingElevation(landing, stairs, floorLevel) - floorLevel;
181→}
182→
183→function buildFloorElevationElements(floor, view) {
184→  const floorElevation = getFloorElevation(floor);
185→  const landings = floor.landings || [];
186→  const stairs = floor.stairs || [];
187→
188→  const landingElevationMap = new Map(
189→    landings.map(l => [l.id, resolveLandingElevation(l, stairs, floorElevation)])
190→  );
191→
192→  return [
193→    ...buildWallRects(floor, view),
194→    ...buildSlabRects(floor, view),
195→    ...buildColumnRects(floor, view),
196→    ...buildBeamRects(floor, view),
197→    ...buildStairRects(floor, view, landingElevationMap),
198→    ...buildDoorRects(floor, view),
199→    ...buildWindowRects(floor, view),
200→  ];
201→}
202→
203→function buildElevationSceneFromFloors(floors, viewMode) {
204→  const view = getElevationView(viewMode);
205→  const stackBounds = getFloorStackBounds(floors);
206→  const elements = floors
207→    .flatMap((floor) => buildFloorElevationElements(floor, view))
208→    .sort((a, b) => b.depth - a.depth);
209→
210→  return {
211→    viewKey: view.key,
212→    title: view.label,
213→    elements,
214→    bounds: computeSceneBounds(elements, stackBounds.minElevation),
215→    groundLevel: stackBounds.minElevation,
216→  };
217→}
218→
219→export function buildElevationScene(floor, viewMode) {
220→  if (!floor) return null;
221→  return buildElevationSceneFromFloors([floor], viewMode);
222→}
223→
224→export function buildProjectElevationScene(project, sourceFloorId, viewMode) {
225→  const sourceFloor = resolveProjectFloor(project, sourceFloorId);
226→  if (!sourceFloor) return null;
227→  return buildElevationSceneFromFloors(getOrderedFloors(project), viewMode);
228→}
