 45→    const dy = end.y - start.y;
 46→    const len = Math.sqrt(dx * dx + dy * dy) || 1;
 47→    return {
 48→      name,
 49→      start,
 50→      end,
 51→      midpoint: mid,
 52→      normal: { x: -dy / len, y: dx / len },
