15→export function createSlabPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport }) {
16→  function commitSlab(points) {
17→    const floor = getFloor(activeFloorId);
18→    if (!floor || points.length < 3) return;
19→
20→    const slab = createSlab(floor.id, points);
21→    dispatch({ type: 'SLAB_ADD', floorId: activeFloorId, slab });
22→    editorDispatch({ type: 'SELECT_OBJECT', id: slab.id, objectType: 'slab' });
23→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Created slab.' });
24→
25→    resetSlabToolState(editorDispatch);
26→  }
27→
28→  return {
29→    onMouseDown(modelPos, e, toolState) {
30→      if (e.button !== 0) return;
31→
32→      const floor = getFloor(activeFloorId);
33→      if (!floor) return;
34→
35→      const points = toolState.slabPoints || [];
36→      const closeDistance = SNAP_DISTANCE_PX / viewport.zoom;
37→
38→      if (points.length === 0) {
39→        editorDispatch({
40→          type: 'UPDATE_TOOL_STATE',
41→          payload: {
42→            slabPoints: [{ x: modelPos.x, y: modelPos.y }],
43→            slabPreviewPoint: { x: modelPos.x, y: modelPos.y },
44→          },
