52→      }
53→
54→      editorDispatch({
55→        type: 'UPDATE_TOOL_STATE',
56→        payload: {
57→          slabPoints: [...points, { x: modelPos.x, y: modelPos.y }],
58→          slabPreviewPoint: { x: modelPos.x, y: modelPos.y },
59→        },
60→      });
61→    },
62→
63→    onMouseMove(modelPos, e, toolState) {
64→      if (!(toolState.slabPoints || []).length) return;
65→      editorDispatch({
66→        type: 'UPDATE_TOOL_STATE',
67→        payload: {
68→          slabPreviewPoint: { x: modelPos.x, y: modelPos.y },
69→        },
70→      });
71→    },
72→
73→    onDoubleClick(modelPos, e, toolState) {
74→      const points = toolState.slabPoints || [];
75→      if (points.length < 3) return;
76→      commitSlab(points);
77→    },
78→
79→    onKeyDown(e) {
80→      if (e.key !== 'Escape') return;
